  `}function ZT(){let e=c.onevone,A=e.activeTimer===1&&e.timerRunning,t=e.activeTimer===2&&e.timerRunning,r=e.player1Finished&&e.player2Finished,a=[{key:"Ctrl+Shift+1",action:"Start timer for Player 1"},{key:"Ctrl+Shift+2",action:"Start timer for Player 2"},{key:"Ctrl+Shift+P",action:"Pause / Resume"},{key:"Ctrl+Shift+R",action:"Reset timer"},{key:"Ctrl+Shift+T",action:"Switch active player"}];return`
